window.KEMTID_DATA.lessons.push(
  {"id":"eng_1","subjectId":"alevel-eng","title":"คำศัพท์และไวยากรณ์พื้นฐาน","body":"Tense ที่ใช้บ่อยในชีวิตประจำวัน (Present Simple, Past Simple) และคำศัพท์ระดับกลางที่ออกสอบบ่อย","formula":"—","detail":{"concept":"Tense บอกว่าเหตุการณ์เกิดขึ้นเมื่อใด ส่วนคำศัพท์ที่ออกสอบบ่อยมักเป็นคำระดับกลางที่ใช้ในชีวิตประจำวัน ไม่ใช่คำยากเฉพาะทาง","explanation":"ลองนึกภาพไดอารี่ที่แบ่งเป็นสองส่วน — หน้า 'กิจวัตรประจำวัน' (สิ่งที่ทำเป็นประจำ ไม่ว่าวันไหน) กับหน้า 'เหตุการณ์เมื่อวาน' (สิ่งที่จบไปแล้วในอดีต) Tense สองแบบนี้แยกกันชัดเจน: Present Simple ใช้กับเหตุการณ์ที่เป็นความจริงทั่วไปหรือทำเป็นประจำ (เติม -s/-es กับประธานเอกพจน์บุรุษที่ 3 เช่น he/she/it) Past Simple ใช้กับเหตุการณ์ที่จบแล้วในอดีต (กริยาปกติเติม -ed เหมือนแปะสติกเกอร์ 'จบแล้ว' ท้ายคำ ส่วนกริยาไม่ปกติต้องท่องจำรูปแยกเพราะไม่มีรูปแบบตายตัว) ข้อสอบมักทดสอบว่าเลือก tense ถูกจากบริบทประโยค (คำบอกเวลาอย่าง every day บ่งบอกกิจวัตร, yesterday บ่งบอกอดีต)","examples":[{"q":"เลือกกริยาที่ถูกต้อง: He usually ___ (walk) to work.","steps":["'usually' บ่งบอกเหตุการณ์ประจำ → ใช้ Present Simple","ประธาน 'He' เอกพจน์บุรุษที่ 3 → เติม -s"],"answer":"walks"},{"q":"เลือกรูปอดีตที่ถูกต้อง: Yesterday, she ___ (eat) breakfast at 7 a.m.","steps":["'Yesterday' บ่งบอกอดีต → ใช้ Past Simple","'eat' เป็นกริยาไม่ปกติ รูปอดีตคือ 'ate' (ไม่ใช่ eated)"],"answer":"ate"},{"q":"เลือกกริยาที่ถูกต้อง: They ___ (play) tennis every Sunday.","steps":["'every Sunday' บ่งบอกกิจวัตร → Present Simple","ประธานพหูพจน์ 'They' ไม่เติม -s"],"answer":"play"},{"q":"เลือกรูปอดีตที่ถูกต้อง: Last night, we ___ (see) a great movie.","steps":["'Last night' บ่งบอกอดีต → Past Simple","'see' เป็นกริยาไม่ปกติ รูปอดีตคือ 'saw'"],"answer":"saw"},{"q":"เลือกกริยาที่ถูกต้อง: My sister ___ (study) English every evening.","steps":["'every evening' บ่งบอกกิจวัตร → Present Simple","'study' ลงท้าย y หลังพยัญชนะ เอกพจน์บุรุษที่3 เปลี่ยนเป็น 'studies'"],"answer":"studies"}]}},
  {"id":"eng_2","subjectId":"alevel-eng","title":"การอ่านจับใจความ","body":"เทคนิคจับคำสำคัญ (keyword) ในคำถามแล้วย้อนกลับไปหาคำตอบในเนื้อเรื่องตรงจุดนั้น โดยไม่ต้องแปลทุกคำ","formula":"—","detail":{"concept":"อ่านจับใจความที่ดีไม่ต้องแปลทุกคำ — จับคำสำคัญในคำถามแล้วสแกนหาคำเดียวกัน (หรือใกล้เคียง) ในเนื้อเรื่อง","explanation":"ลองนึกภาพนักสืบที่ไม่ต้องอ่านสำนวนคดีทั้งเล่ม แค่รู้ว่าจะมองหาอะไร (ใคร ทำอะไร ที่ไหน เมื่อไหร่) แล้วสแกนหาคำเหล่านั้นในหน้ากระดาษ — นั่นคือเทคนิคการอ่านจับใจความที่ดี ไม่ต้องแปลทุกคำ เทคนิคคือ: อ่านคำถามก่อนอ่านเนื้อเรื่องทั้งหมด เพื่อรู้ว่าต้องมองหาอะไร จับคำสำคัญ (keyword) ในคำถาม เช่น ชื่อคน เวลา สถานที่ แล้วสแกนหาคำนั้นในเนื้อเรื่องแทนการอ่านทุกบรรทัดตั้งแต่ต้นจนจบ คำตอบมักอยู่ใกล้ๆ จุดที่พบคำสำคัญนั้นเสมอ ไม่ใช่กระจัดกระจายทั่วทั้งย่อหน้า","examples":[{"q":"Passage: 'Anan plays football on Mondays and Wednesdays.' Question: When does Anan play football?","steps":["คำสำคัญในคำถามคือ 'play football' และ 'when'","สแกนหาคำเดียวกันในเนื้อเรื่อง พบ 'plays football on Mondays and Wednesdays'"],"answer":"On Mondays and Wednesdays"},{"q":"Passage: 'The museum opens at 9 a.m. and closes at 5 p.m.' Question: What time does the museum close?","steps":["คำสำคัญคือ 'close' และ 'what time'","สแกนหาคำว่า 'closes' ในเนื้อเรื่อง พบ 'closes at 5 p.m.'"],"answer":"5 p.m."},{"q":"Passage: \"Nok works as a chef at a hotel restaurant. She creates new menu items every month.\" Question: What does Nok create every month?","steps":["คำสำคัญคือ 'create' และ 'every month'","เนื้อเรื่องระบุ 'creates new menu items every month'"],"answer":"New menu items"},{"q":"Passage: \"The library is open from Monday to Saturday, but closed on Sunday.\" Question: Which day is the library closed?","steps":["คำสำคัญคือ 'closed'","เนื้อเรื่องระบุ 'closed on Sunday'"],"answer":"Sunday"},{"q":"Passage: \"Boonmee grows rice on his farm. He harvests the crop twice a year.\" Question: How many times a year does Boonmee harvest his crop?","steps":["คำสำคัญคือ 'harvest' และ 'how many times'","เนื้อเรื่องระบุ 'harvests the crop twice a year'"],"answer":"Twice a year"}]}}

);

window.KEMTID_DATA.quizzes.push(
  {"id":"q_alevel_eng_1","subjectId":"alevel-eng","title":"A-Level อังกฤษ · ชุดฝึกหัด 1","topic":"ไวยากรณ์และคำศัพท์พื้นฐาน","difficulty":"ง่าย","intro":{"concept":"ไวยากรณ์และคำศัพท์พื้นฐานเป็นรากฐานของทุกทักษะภาษาอังกฤษ ข้อสอบมักทดสอบ tense ที่ใช้บ่อยในชีวิตประจำวันและคำศัพท์ระดับกลาง ไม่ต้องรู้คำยากมาก แค่รู้ให้แม่นและสังเกตบริบทประโยค","worked":{"q":"Choose the correct word: They ___ football every weekend.","steps":["ประธาน \"They\" เป็นพหูพจน์ ไม่ต้องเติม -s ที่กริยา","กริยาที่ถูกต้องคือรูปเดิมของ \"play\""],"answer":"play"}},"questions":[{"q":"Choose the correct word: She ___ to school every day.","choices":["go","goes","going","gone"],"correct":1,"hint":"ประธาน \"She\" เป็นเอกพจน์บุรุษที่ 3 กริยาใน Present Simple ต้องเติมอะไร","steps":["ประโยคนี้เป็น Present Simple (เหตุการณ์ประจำ \"every day\")","ประธาน \"She\" เป็นเอกพจน์บุรุษที่สาม ต้องเติม -s หรือ -es ที่กริยา","\"go\" เติม -es เป็น \"goes\""],"tip":"กฎ Present Simple: ประธานเอกพจน์บุรุษที่ 3 (he/she/it) ต้องเติม -s/-es ที่กริยาเสมอ เป็นจุดที่พลาดกันบ่อยที่สุด"},{"q":"What is the past tense of 'go'?","choices":["goed","gone","went","going"],"correct":2,"hint":"\"go\" เป็นกริยาไม่ปกติ (irregular verb) ต้องจำรูปอดีตแยกต่างหาก ไม่ใช่เติม -ed","steps":["\"go\" เป็นกริยาไม่ปกติ ไม่สามารถเติม -ed ได้","รูปอดีตของ \"go\" คือ \"went\"","\"gone\" เป็นรูป past participle (ใช้กับ have/has) ไม่ใช่รูปอดีตธรรมดา"],"tip":"กริยาไม่ปกติต้องท่องจำเป็นชุด (go-went-gone) แยกจากกริยาปกติที่แค่เติม -ed"},{"q":"Choose the word closest in meaning to 'huge'.","choices":["tiny","enormous","narrow","quiet"],"correct":1,"hint":"\"huge\" แปลว่าใหญ่มาก ลองหาคำที่มีความหมายใกล้เคียงกับขนาดใหญ่","steps":["\"huge\" หมายถึงมีขนาดใหญ่มาก","\"tiny\" หมายถึงเล็กมาก (ตรงข้าม) \"narrow\" หมายถึงแคบ \"quiet\" หมายถึงเงียบ","\"enormous\" หมายถึงใหญ่มากเช่นกัน จึงเป็นคำที่ความหมายใกล้เคียงที่สุด"],"tip":"เมื่อไม่แน่ใจคำศัพท์ ให้ตัดคำที่ความหมายตรงข้ามหรือไม่เกี่ยวข้องออกก่อน จะเหลือตัวเลือกให้พิจารณาน้อยลง"},{"q":"Complete the sentence: I have lived here ___ five years.","choices":["since","for","from","at"],"correct":1,"hint":"เปรียบเทียบ \"for\" กับ \"since\" — คำไหนใช้กับ \"ระยะเวลา\" (five years) และคำไหนใช้กับ \"จุดเริ่มต้น\"","steps":["\"for\" ใช้กับช่วงระยะเวลา เช่น for five years, for a week","\"since\" ใช้กับจุดเริ่มต้นของเวลา เช่น since 2020, since Monday","\"five years\" เป็นระยะเวลา จึงใช้ \"for\""],"tip":"จำคู่นี้ให้แม่น: for + ระยะเวลา (for 3 days), since + จุดเริ่มต้น (since Monday) เป็นจุดที่ออกสอบบ่อยมาก"}]},
  {"id":"q_alevel_eng_2","subjectId":"alevel-eng","title":"A-Level อังกฤษ · ชุดฝึกหัด 2","topic":"การอ่านจับใจความ","difficulty":"กลาง","intro":{"concept":"การอ่านจับใจความไม่ต้องแปลทุกคำ ให้จับคำสำคัญ (keyword) ในคำถามแล้วย้อนกลับไปหาคำตอบในเนื้อเรื่องตรงจุดนั้น ไม่ต้องอ่านซ้ำทั้งหมด","worked":{"q":"Passage: \"Malee is a farmer. She grows rice and vegetables. She wakes up early to water her plants.\" Question: What does Malee grow?","steps":["หาคำสำคัญในคำถามคือ \"grow\"","ย้อนกลับไปหาประโยคที่มีคำว่า grow ในเนื้อเรื่อง","พบว่า \"She grows rice and vegetables\""],"answer":"Rice and vegetables"}},"questions":[{"q":"Passage: \"Somchai wakes up at 6 a.m. every day. He eats breakfast, then walks to school. School starts at 8 a.m.\" Question: What time does Somchai wake up?","choices":["6 a.m.","7 a.m.","8 a.m.","9 a.m."],"correct":0,"hint":"คำถามถามเรื่อง \"wake up\" ลองหาประโยคแรกของเนื้อเรื่อง","steps":["คำสำคัญในคำถามคือ \"wake up\"","ประโยคแรกของเนื้อเรื่องระบุว่า \"Somchai wakes up at 6 a.m.\"","คำตอบคือ 6 a.m. โดยตรง"],"tip":"คำถามแบบ \"when/what time\" มักตอบได้จากการหาตัวเลข/เวลาที่ตรงกับคำสำคัญในเนื้อเรื่องโดยไม่ต้องตีความ"},{"q":"Passage เดียวกับข้อก่อนหน้า: How does Somchai get to school?","choices":["By bus","By car","He walks","By bike"],"correct":2,"hint":"หาคำที่เกี่ยวกับการเดินทางไปโรงเรียนในเนื้อเรื่อง","steps":["คำสำคัญในคำถามคือ \"get to school\"","เนื้อเรื่องระบุว่า \"then walks to school\"","คำตอบคือ เขาเดินไป (He walks)"],"tip":"ระวังคำตอบหลอกที่เป็นวิธีเดินทางทั่วไป (by bus, by car) แต่ไม่ตรงกับสิ่งที่เนื้อเรื่องระบุจริง"},{"q":"Passage: \"Nichakorn works at a hospital. She is a nurse. Every morning, she checks on her patients and gives them medicine.\" Question: What is Nichakorn's job?","choices":["Doctor","Nurse","Teacher","Engineer"],"correct":1,"hint":"เนื้อเรื่องบอกอาชีพของเธอตรงๆ ในประโยคที่สอง","steps":["คำสำคัญในคำถามคือ \"job\"","เนื้อเรื่องระบุตรงๆ ว่า \"She is a nurse\"","คำตอบคือ Nurse"],"tip":"คำถามถามอาชีพ/ตำแหน่งมักตอบได้จากประโยคที่มีคำว่า \"is a...\" ตรงๆ ไม่ต้องอนุมาน"},{"q":"Passage: \"...On weekends, she likes to read books and go swimming.\" Question: What does Nichakorn like to do on weekends?","choices":["Cook and dance","Read books and go swimming","Watch movies","Play sports"],"correct":1,"hint":"หาประโยคที่มีคำว่า \"weekends\" ในเนื้อเรื่อง","steps":["คำสำคัญในคำถามคือ \"weekends\"","เนื้อเรื่องระบุว่า \"On weekends, she likes to read books and go swimming\"","คำตอบคือ Read books and go swimming"],"tip":"เมื่อคำถามมีคำเชื่อมเวลา (on weekends, in the morning) ให้หาคำเดียวกันในเนื้อเรื่องก่อน จะเจอคำตอบเร็วที่สุด"}]},
  {"id":"q_alevel_eng_3","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเติมข้อความให้สมบูรณ์","topic":"ทักษะการเขียน (Text Completion)","difficulty":"ยาก","intro":{"concept":"โจทย์เติมข้อความระดับ A-Level เน้นคำเชื่อม (connector) และวลีสำเร็จรูปที่ใช้เชื่อมความคิดให้ประโยค/ย่อหน้าลื่นไหลและมีเหตุผลถูกต้อง ต้องอ่านทั้งประโยคเพื่อดูความสัมพันธ์เชิงเหตุผล ไม่ใช่แค่ไวยากรณ์จุดเดียว","worked":{"q":"The report needs to be submitted ___ Friday at the latest.","steps":["ประโยคนี้พูดถึงกำหนดส่งงาน (deadline) ไม่ใช่ระยะเวลาต่อเนื่อง","\"by\" ใช้กับกำหนดเวลาสุดท้าย (deadline) ส่วน \"until\" ใช้กับการกระทำที่ดำเนินต่อเนื่องจนถึงจุดหนึ่ง","วลี \"at the latest\" ยืนยันว่าเป็นกำหนดเวลาสุดท้าย จึงใช้ \"by\""],"answer":"by"}},"questions":[{"q":"The report needs to be submitted ___ Friday at the latest.","choices":["by","until","since","during"],"correct":0,"hint":"เปรียบเทียบ \"by\" (กำหนดเวลาสุดท้าย) กับ \"until\" (ดำเนินต่อเนื่องจนถึง) — วลี \"at the latest\" ช่วยบอกใบ้ความหมาย","steps":["\"by + เวลา\" ใช้กับกำหนดเวลาสุดท้าย (deadline) เช่น by Friday","\"until + เวลา\" ใช้กับการกระทำที่ดำเนินต่อเนื่องไปจนถึงเวลานั้น เช่น wait until Friday","วลี \"at the latest\" ในประโยคยืนยันว่าเป็นกำหนดส่งสุดท้าย ไม่ใช่การกระทำต่อเนื่อง","คำตอบที่ถูกต้องคือ \"by\""],"tip":"\"by\" กับ \"until\" เป็นคู่คำที่ข้อสอบชอบเทียบ — by เน้น 'เสร็จภายในเวลานั้น' ส่วน until เน้น 'ดำเนินต่อไปจนถึงเวลานั้น'"},{"q":"___ she was tired, she finished her homework before going to bed.","choices":["Although","Because","So","Unless"],"correct":0,"hint":"ประโยคนี้มีความขัดแย้งกัน (เหนื่อยแต่ยังทำการบ้านจนเสร็จ) หาคำเชื่อมที่แสดงความขัดแย้ง","steps":["สังเกตความสัมพันธ์ของสองเหตุการณ์: เหนื่อย (tired) กับ ทำการบ้านจนเสร็จ (finished homework) — เป็นความขัดแย้งกัน","\"Because\" และ \"So\" แสดงเหตุ-ผล ไม่ตรงกับความสัมพันธ์แบบขัดแย้ง","\"Unless\" แสดงเงื่อนไข ก็ไม่ตรงกับบริบทนี้","\"Although\" แสดงความขัดแย้ง (แม้ว่า...ก็ยัง...) ตรงกับความหมายของประโยคที่สุด"],"tip":"กลุ่มคำแสดงความขัดแย้ง (although, though, despite, in spite of) มักเจอในประโยคที่ผลลัพธ์ตรงข้ามกับสิ่งที่คาดหวัง"},{"q":"The company's profits increased significantly, ___ resulted in higher employee bonuses.","choices":["which","who","whose","what"],"correct":0,"hint":"ช่องว่างนี้ต้องการ relative pronoun ที่อ้างถึงเหตุการณ์ทั้งประโยคก่อนหน้า (การที่กำไรเพิ่มขึ้น) ไม่ใช่อ้างถึงบุคคล","steps":["\"who\" และ \"whose\" ใช้อ้างอิงถึงบุคคล ไม่เข้ากับบริบทนี้ (อ้างถึงเหตุการณ์)","\"what\" ไม่ใช้เป็น relative pronoun เชื่อมประโยคแบบนี้","\"which\" ใช้อ้างอิงถึงสิ่งของหรือทั้งประโยคที่กล่าวมาก่อนหน้าได้ ตรงกับบริบท (กำไรเพิ่มขึ้น ซึ่งส่งผลให้โบนัสสูงขึ้น)"],"tip":"เมื่อ relative clause อ้างอิงถึง 'ทั้งประโยคหรือเหตุการณ์ที่กล่าวมาก่อนหน้า' (ไม่ใช่คำนามคำเดียว) ให้ใช้ \"which\" เสมอ ไม่ใช้ \"who\""},{"q":"He is not only intelligent ___ also hardworking.","choices":["and","but","or","so"],"correct":1,"hint":"นี่คือโครงสร้างสำเร็จรูป \"not only...but also...\" ที่ต้องจำเป็นคู่ตายตัว","steps":["โครงสร้าง \"not only A but also B\" เป็นวลีสำเร็จรูปที่ใช้เชื่อมคุณสมบัติสองอย่างเข้าด้วยกัน","คำเชื่อมที่ใช้คู่กับ \"not only\" ต้องเป็น \"but\" เสมอ ไม่ใช่ and/or/so","คำตอบที่ถูกต้องคือ \"but\""],"tip":"วลี \"not only...but also...\" ต้องจำเป็นคู่ตายตัวเหมือนวลีสำเร็จรูปอื่นๆ (เช่น both...and, either...or) ห้ามสลับคำเชื่อมในคู่"}]},
  {"id":"q_alevel_eng_4","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเรียงลำดับประโยค","topic":"ทักษะการเขียน (Paragraph/Sentence Ordering)","difficulty":"ยาก","intro":{"concept":"โจทย์เรียงลำดับประโยค/ย่อหน้าใช้การสังเกตคำเชื่อมที่บ่งบอกลำดับ (First/Firstly, Then/After that, Next, Finally/In conclusion) และความสัมพันธ์เชิงเหตุผล (however, so, as a result) เพื่อจัดเรียงประโยคให้เป็นเนื้อความที่ลื่นไหลและสมเหตุสมผล","worked":{"q":"เรียงลำดับให้ถูกต้อง: (A) First, mix the flour and sugar. (B) Finally, bake it for 30 minutes. (C) Then, add the eggs and stir well. (D) Next, pour the mixture into a pan.","steps":["สังเกตคำเชื่อมบอกลำดับในแต่ละประโยค: First(A), Then(C), Next(D), Finally(B)","คำเหล่านี้บ่งบอกลำดับขั้นตอนอย่างชัดเจนตามลำดับ First→Then→Next→Finally","จัดเรียงตามลำดับคำเชื่อม: A-C-D-B"],"answer":"A-C-D-B"}},"questions":[{"q":"เรียงลำดับประโยคต่อไปนี้ให้เป็นย่อหน้าที่สมเหตุสมผล: (A) However, it started raining heavily. (B) We planned to go to the beach. (C) So we decided to stay home instead. (D) We were very disappointed.","choices":["B-A-D-C","B-A-C-D","A-B-C-D","B-D-A-C"],"correct":1,"hint":"เริ่มจากประโยคที่ตั้งเรื่อง (แผนการ) แล้วตามด้วยเหตุการณ์ที่ขัดขวางแผน แล้วผลลัพธ์ที่ตามมา","steps":["ประโยคที่ตั้งเรื่องควรมาก่อนคือ (B) เราวางแผนจะไปทะเล","ตามด้วย (A) \"However\" บ่งบอกเหตุการณ์ที่ขัดขวางแผน คือฝนตกหนัก","ตามด้วย (C) \"So\" บ่งบอกผลลัพธ์จากเหตุการณ์นั้น คือตัดสินใจอยู่บ้านแทน","ปิดท้ายด้วย (D) ความรู้สึกผิดหวัง — ลำดับที่ถูกต้องคือ B-A-C-D"],"tip":"คำเชื่อม \"However\" มักตามหลังการตั้งเรื่อง/แผนการ ส่วน \"So\" มักตามหลังเหตุการณ์ที่ทำให้ต้องเปลี่ยนแผน ใช้คำเชื่อมเป็นตัวนำทางลำดับได้เสมอ"},{"q":"เรียงลำดับขั้นตอนการอบคุกกี้ให้ถูกต้อง: (A) Firstly, preheat the oven to 180°C. (B) After that, place the tray in the oven for 20 minutes. (C) Secondly, arrange the cookies on a tray. (D) Finally, let the cookies cool down before serving.","choices":["A-C-B-D","A-B-C-D","C-A-B-D","D-A-C-B"],"correct":0,"hint":"คำเชื่อมบอกลำดับตรงตัวอยู่แล้ว: Firstly, Secondly, After that, Finally — จัดเรียงตามนั้นได้เลย","steps":["\"Firstly\" (A) ต้องมาก่อนเสมอ — อุ่นเตาอบ","\"Secondly\" (C) ตามมาเป็นลำดับที่สอง — จัดคุกกี้บนถาด","\"After that\" (B) ตามมาเป็นลำดับที่สาม — นำเข้าเตาอบ","\"Finally\" (D) ปิดท้าย — ปล่อยให้เย็นก่อนเสิร์ฟ — ลำดับที่ถูกต้องคือ A-C-B-D"],"tip":"เมื่อโจทย์ให้คำเชื่อมลำดับตรงตัว (Firstly, Secondly, Finally) ให้จัดเรียงตามคำเชื่อมได้เลยโดยไม่ต้องตีความเนื้อหาลึก"},{"q":"เรียงลำดับประโยคให้เป็นย่อหน้าที่สมเหตุสมผล: (A) In conclusion, renewable energy is essential for a sustainable future. (B) Solar and wind power are two popular examples of renewable energy. (C) Renewable energy comes from natural sources that do not run out. (D) These sources produce electricity without releasing harmful pollutants.","choices":["C-B-D-A","A-B-C-D","B-C-D-A","C-D-B-A"],"correct":0,"hint":"เริ่มจากประโยคนิยาม (definition) ก่อน แล้วตามด้วยตัวอย่าง ประโยชน์ และสรุปท้ายสุด","steps":["ประโยคนิยามควรมาก่อน คือ (C) อธิบายว่าพลังงานหมุนเวียนคืออะไร","ตามด้วย (B) ยกตัวอย่างประเภทของพลังงานหมุนเวียน","ตามด้วย (D) อธิบายประโยชน์เพิ่มเติม (ไม่ปล่อยมลพิษ)","ปิดท้ายด้วย (A) \"In conclusion\" ซึ่งเป็นคำเชื่อมสรุป ต้องอยู่ท้ายสุดเสมอ — ลำดับที่ถูกต้องคือ C-B-D-A"],"tip":"วลี \"In conclusion\" หรือ \"To sum up\" เป็นสัญญาณที่ชัดเจนที่สุดว่าประโยคนั้นต้องอยู่ท้ายสุดของย่อหน้าเสมอ"},{"q":"เรียงลำดับประโยคเกี่ยวกับชีวิตของ Malee ให้ถูกต้อง: (A) Then, she moved to a small apartment near her office. (B) Malee graduated from university last year. (C) Now, she works as an accountant in a bank. (D) After graduation, she started looking for a job.","choices":["B-D-A-C","B-A-D-C","D-B-A-C","B-D-C-A"],"correct":0,"hint":"นี่คือลำดับเหตุการณ์ตามเวลา (chronological order) ในชีวิตคนคนหนึ่ง ไล่จากอดีตไปปัจจุบัน","steps":["เหตุการณ์แรกสุดตามเวลาคือ (B) เรียนจบมหาวิทยาลัย","ตามด้วย (D) \"After graduation\" คือหางานทำ","ตามด้วย (A) \"Then\" คือย้ายไปอยู่อพาร์ตเมนต์ใกล้ที่ทำงาน","ปิดท้ายด้วย (C) \"Now\" คือสถานะปัจจุบัน ทำงานเป็นนักบัญชี — ลำดับที่ถูกต้องคือ B-D-A-C"],"tip":"คำบอกเวลา (Then, After that, Now) เป็นตัวช่วยจัดลำดับเหตุการณ์ชีวประวัติได้ดีที่สุด ไล่จากอดีตที่สุดไปหาปัจจุบันเสมอ"}]},
  {"id":"q_alevel_eng_5","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านโฆษณาและรีวิว","topic":"ทักษะการอ่าน (Advertisement & Review)","difficulty":"กลาง","intro":{"concept":"โฆษณาเน้นให้ข้อมูลที่เป็นประโยชน์ต่อผู้ซื้อ เช่น ราคา ส่วนลด และช่วงเวลา ให้จับตัวเลขและเงื่อนไขให้แม่น ส่วนรีวิวเน้นความคิดเห็นและประสบการณ์ส่วนตัว มักมีทั้งข้อดีและข้อเสียปนกัน ต้องแยกให้ออกว่าส่วนไหนเป็นคำชม ส่วนไหนเป็นคำติ","worked":{"q":"Advertisement: \"SUMMER SALE! Get 30% off all shoes at StepUp Store. Valid from June 1-15 only.\" Question: What is the discount offered?","steps":["คำสำคัญในคำถามคือ \"discount\"","เนื้อโฆษณาระบุตรงๆ ว่า \"Get 30% off\"","คำตอบคือ 30%"],"answer":"30%"}},"questions":[{"q":"Advertisement: \"SUMMER SALE! Get 30% off all shoes at StepUp Store. Valid from June 1-15 only. Visit our website or store location at 123 Main Street. Limited stock available!\" Question: How long is the sale valid?","choices":["1 day","15 days","30 days","1 month"],"correct":1,"hint":"หาช่วงวันที่ที่ระบุในโฆษณา แล้วนับจำนวนวัน","steps":["เนื้อโฆษณาระบุว่า \"Valid from June 1-15 only\"","นับจำนวนวันจาก 1 ถึง 15 มิถุนายน","รวมเป็น 15 วัน"],"tip":"โฆษณามักระบุช่วงเวลาที่ข้อเสนอมีผล (validity period) ให้หาตัวเลขวันที่สองจุดแล้วคำนวณระยะห่างระหว่างวัน"},{"q":"Review: \"This restaurant has amazing food, but the service was very slow. I waited 40 minutes for my order. I would still recommend it for the food quality, just be patient.\" Question: What is the main complaint in this review?","choices":["The food tastes bad","The service was slow","The restaurant is too expensive","The location is hard to find"],"correct":1,"hint":"หาส่วนที่มีคำว่า \"but\" ในรีวิว ซึ่งมักบ่งบอกจุดที่เป็นข้อเสีย","steps":["รีวิวเริ่มด้วยคำชม (\"amazing food\") แล้วตามด้วย \"but\" ซึ่งบ่งบอกความขัดแย้ง/ข้อเสีย","หลัง \"but\" ระบุว่า \"the service was very slow\" และรอ 40 นาที","คำตอบคือ การบริการช้า (slow service)"],"tip":"คำว่า \"but\" ในรีวิวเป็นสัญญาณสำคัญที่บอกว่ากำลังจะเปลี่ยนจากคำชมไปเป็นคำติ อ่านส่วนหลัง \"but\" ให้ละเอียด"},{"q":"Review เดียวกับข้อก่อนหน้า: What does the reviewer recommend the restaurant for?","choices":["Fast service","Food quality","Low prices","Nice decoration"],"correct":1,"hint":"หาส่วนท้ายของรีวิวที่มีคำว่า \"recommend\"","steps":["คำสำคัญในคำถามคือ \"recommend\"","รีวิวระบุว่า \"I would still recommend it for the food quality\"","คำตอบคือ คุณภาพอาหาร (food quality)"],"tip":"รีวิวที่มีทั้งข้อดีข้อเสีย มักสรุปท้ายว่า \"แนะนำเพราะอะไร\" หรือ \"ไม่แนะนำเพราะอะไร\" ให้อ่านประโยคสรุปท้ายเสมอเพื่อจับใจความหลัก"},{"q":"Advertisement เดียวกับข้อแรก: Where is the store located?","choices":["456 Second Avenue","123 Main Street","789 Park Road","321 Center Boulevard"],"correct":1,"hint":"หาที่อยู่ที่ระบุไว้ในโฆษณา","steps":["เนื้อโฆษณาระบุว่า \"Visit our website or store location at 123 Main Street\"","คำตอบคือ 123 Main Street"],"tip":"โฆษณามักมีรายละเอียดติดต่อ (ที่อยู่, เว็บไซต์, เบอร์โทร) อยู่ท้ายข้อความเสมอ หาข้อมูลติดต่อได้จากส่วนนี้"}]},
  {"id":"q_alevel_eng_6","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านข่าวและบทความ","topic":"ทักษะการอ่าน (News & Article)","difficulty":"กลาง","intro":{"concept":"ข่าวเน้นข้อเท็จจริง (who, what, when, where, how much) ให้จับตัวเลขและชื่อเฉพาะให้แม่น ส่วนบทความเชิงให้ความรู้ (เช่นบทความสุขภาพ) มักมีข้อเสนอแนะหรือคำแนะนำจากผู้เชี่ยวชาญ ให้จับคำว่า \"recommend\", \"suggest\", \"expert\" เป็นจุดสังเกต","worked":{"q":"News: \"Bangkok will build a new public park in the city center next year. The project will cost 50 million baht.\" Question: How much will the project cost?","steps":["คำสำคัญในคำถามคือ \"cost\"","ข่าวระบุตรงๆ ว่า \"will cost 50 million baht\"","คำตอบคือ 50 ล้านบาท"],"answer":"50 million baht"}},"questions":[{"q":"News: \"Bangkok will build a new public park in the city center next year. The project will cost 50 million baht and is expected to be completed within 18 months. City officials say the park will include walking trails and a children's playground.\" Question: How long will the project take to complete?","choices":["6 months","12 months","18 months","24 months"],"correct":2,"hint":"หาตัวเลขที่เกี่ยวกับระยะเวลาในการสร้างในข่าว","steps":["คำสำคัญในคำถามคือ \"complete\"","ข่าวระบุว่า \"expected to be completed within 18 months\"","คำตอบคือ 18 เดือน"],"tip":"ข่าวมักมีตัวเลขหลายตัวปนกัน (งบประมาณ ระยะเวลา จำนวน) อ่านคำถามให้ชัดว่าถามตัวเลขไหนก่อนย้อนกลับไปหาในเนื้อข่าว"},{"q":"News เดียวกับข้อก่อนหน้า: What will the new park include?","choices":["A swimming pool and a gym","Walking trails and a children's playground","A shopping mall and a cinema","A parking lot and a bus station"],"correct":1,"hint":"หาประโยคสุดท้ายของข่าวที่พูดถึงสิ่งอำนวยความสะดวกในสวน","steps":["คำสำคัญในคำถามคือ \"include\"","ข่าวระบุว่า \"the park will include walking trails and a children's playground\"","คำตอบคือ ทางเดินและสนามเด็กเล่น"],"tip":"คำว่า \"include\" ในข่าวมักตามด้วยรายการสิ่งของ/สิ่งอำนวยความสะดวกโดยตรง อ่านสิ่งที่ตามมาหลังคำนี้เป็นคำตอบได้เลย"},{"q":"Article: \"Regular exercise not only improves physical health but also reduces stress and improves sleep quality. Experts recommend at least 150 minutes of moderate exercise per week.\" Question: How much exercise do experts recommend per week?","choices":["50 minutes","100 minutes","150 minutes","200 minutes"],"correct":2,"hint":"หาตัวเลขที่ตามหลังคำว่า \"recommend\" ในบทความ","steps":["คำสำคัญในคำถามคือ \"recommend\" และ \"per week\"","บทความระบุว่า \"Experts recommend at least 150 minutes of moderate exercise per week\"","คำตอบคือ 150 นาที"],"tip":"บทความเชิงให้ความรู้มักมีตัวเลขคำแนะนำจากผู้เชี่ยวชาญ (เช่น ปริมาณที่แนะนำ) ตามหลังคำว่า \"recommend\" หรือ \"suggest\" เสมอ"},{"q":"Article เดียวกับข้อก่อนหน้า: According to the article, what are the benefits of regular exercise?","choices":["Only physical health","Physical health, reduced stress, and better sleep","Only weight loss","Only muscle growth"],"correct":1,"hint":"หาทุกประโยชน์ที่บทความกล่าวถึง ไม่ใช่แค่ข้อแรก สังเกตคำว่า \"not only...but also\"","steps":["บทความใช้โครงสร้าง \"not only...but also\" เพื่อระบุประโยชน์หลายข้อพร้อมกัน","ประโยชน์ที่กล่าวถึงคือ \"improves physical health\", \"reduces stress\", และ \"improves sleep quality\"","คำตอบที่ครบถ้วนที่สุดคือ สุขภาพกาย ลดความเครียด และนอนหลับดีขึ้น"],"tip":"โครงสร้าง \"not only A but also B\" บ่งบอกว่ามีประโยชน์/ข้อเท็จจริงมากกว่า 1 อย่าง อย่าเลือกคำตอบที่มีแค่ข้อเดียวถ้าบทความกล่าวถึงหลายข้อ"}]},
  {"id":"q_alevel_eng_7","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านข้อมูลตัวเลข (กราฟ/แผนภูมิ)","topic":"ทักษะการอ่าน (Graph/Chart Data)","difficulty":"ยาก","intro":{"concept":"โจทย์กราฟ/แผนภูมิวัดว่าเราดึงข้อมูลตัวเลขจากข้อความหรือตารางที่บรรยายเป็นภาษาอังกฤษได้แม่นยำหรือไม่ เทคนิคคือไล่จับคู่ 'หมวดหมู่-ตัวเลข' ให้ครบทุกคู่ก่อนตอบคำถาม แล้วเปรียบเทียบเฉพาะคู่ที่คำถามต้องการ","worked":{"q":"Data: A survey of 100 students' favorite subjects: Math - 40 students, Science - 30 students, English - 20 students, Art - 10 students. Question: Which subject is the most popular?","steps":["ไล่เทียบตัวเลขของแต่ละวิชา: Math=40, Science=30, English=20, Art=10","หาค่าที่มากที่สุดในกลุ่ม","Math มีค่ามากที่สุด (40 คน)"],"answer":"Math"}},"questions":[{"q":"Data: A survey of 100 students' favorite subjects: Math - 40 students, Science - 30 students, English - 20 students, Art - 10 students. Question: How many more students prefer Science than English?","choices":["5","10","20","30"],"correct":1,"hint":"หาตัวเลขของ Science กับ English แยกกันก่อน แล้วลบกัน","steps":["จำนวนนักเรียนที่ชอบ Science = 30 คน","จำนวนนักเรียนที่ชอบ English = 20 คน","ผลต่าง = 30−20 = 10 คน"],"tip":"คำถามแบบ \"how many more...than...\" ต้องการผลต่าง (ลบ) ไม่ใช่ผลรวม (บวก) อ่านคำถามให้ครบก่อนเลือกวิธีคำนวณ"},{"q":"Data: Company sales by quarter: Q1 - $50,000, Q2 - $65,000, Q3 - $80,000, Q4 - $70,000. Question: In which quarter were sales the highest?","choices":["Q1","Q2","Q3","Q4"],"correct":2,"hint":"ไล่เทียบตัวเลขยอดขายทั้ง 4 ไตรมาส หาค่าที่มากที่สุด","steps":["ไล่เทียบยอดขาย: Q1=$50,000, Q2=$65,000, Q3=$80,000, Q4=$70,000","หาค่าที่มากที่สุดในกลุ่ม","Q3 มียอดขายสูงสุดที่ $80,000"],"tip":"เขียนตัวเลขทั้งหมดเรียงกันเป็นแถวก่อนเปรียบเทียบ จะเห็นค่าสูงสุด/ต่ำสุดได้ชัดเจนกว่าเทียบทีละคู่ในหัว"},{"q":"Data เดียวกับข้อก่อนหน้า: What was the increase in sales from Q1 to Q2?","choices":["$10,000","$15,000","$20,000","$25,000"],"correct":1,"hint":"หายอดขาย Q1 กับ Q2 แยกกันก่อน แล้วหาผลต่าง","steps":["ยอดขาย Q1 = $50,000","ยอดขาย Q2 = $65,000","ส่วนที่เพิ่มขึ้น = $65,000−$50,000 = $15,000"],"tip":"คำว่า \"increase from A to B\" ต้องการผลต่างระหว่างสองค่านั้นโดยเฉพาะ ไม่ใช่ค่าใดค่าหนึ่งเพียงอย่างเดียว"},{"q":"Data: A survey of 100 students' favorite subjects: Math - 40 students, Science - 30 students, English - 20 students, Art - 10 students. Question: What percentage of students prefer Art?","choices":["5%","10%","20%","40%"],"correct":1,"hint":"ใช้สูตรเปอร์เซ็นต์ = (จำนวนที่สนใจ/จำนวนทั้งหมด)×100","steps":["จำนวนนักเรียนที่ชอบ Art = 10 คน จากทั้งหมด 100 คน","ใช้สูตร (10/100)×100","คำนวณ = 10%"],"tip":"เมื่อจำนวนทั้งหมดเป็น 100 พอดี การหาเปอร์เซ็นต์ทำได้ง่ายมาก เพราะจำนวนคนตรงกับเปอร์เซ็นต์โดยตรง"}]},
  {"id":"q_alevel_eng_8","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การหาข้อผิดพลาดในประโยค","topic":"ทักษะการเขียน (Error Identification)","difficulty":"ยาก","intro":{"concept":"โจทย์หาข้อผิดพลาดแบ่งประโยคเป็น 4 ส่วน (A)(B)(C)(D) ให้หาว่าส่วนใดผิดหลักไวยากรณ์ เทคนิคคือตรวจสอบความสอดคล้องระหว่างประธาน-กริยา (subject-verb agreement), tense ให้ตรงกันทั้งประโยค, และการใช้คำบุพบท/คำเชื่อมที่ถูกต้อง ทีละส่วนจนกว่าจะเจอจุดที่ขัดกับกฎไวยากรณ์","worked":{"q":"She (A)don't like (B)coffee, but (C)she loves (D)tea. ส่วนใดผิดหลักไวยากรณ์","steps":["ตรวจสอบความสอดคล้องประธาน-กริยาในแต่ละส่วน","ประธาน \"She\" เป็นเอกพจน์บุรุษที่ 3 ต้องใช้ \"doesn't\" ไม่ใช่ \"don't\"","ส่วน (A) จึงเป็นส่วนที่ผิด"],"answer":"(A)"}},"questions":[{"q":"The children (A)was playing (B)in the park (C)when it (D)started to rain. ส่วนใดผิดหลักไวยากรณ์","choices":["(A)","(B)","(C)","(D)"],"correct":0,"hint":"ตรวจสอบว่าประธาน \"The children\" เป็นเอกพจน์หรือพหูพจน์ แล้วดูว่ากริยา \"was\" สอดคล้องหรือไม่","steps":["\"The children\" เป็นประธานรูปพหูพจน์ (children คือพหูพจน์ของ child)","กริยาที่สอดคล้องกับประธานพหูพจน์ใน past continuous คือ \"were\" ไม่ใช่ \"was\"","ส่วน (A) \"was playing\" จึงผิด ต้องเป็น \"were playing\""],"tip":"คำนามที่เป็นพหูพจน์ไม่ปกติ (children, people, men, women) มักถูกใช้หลอกด้วยกริยาเอกพจน์ ต้องระวังเป็นพิเศษ"},{"q":"He is (A)one of the most (B)talented player (C)in the (D)team. ส่วนใดผิดหลักไวยากรณ์","choices":["(A)","(B)","(C)","(D)"],"correct":1,"hint":"โครงสร้าง \"one of the most + adjective + ???\" ต้องตามด้วยคำนามรูปเอกพจน์หรือพหูพจน์","steps":["โครงสร้าง \"one of the + adjective ที่สุด + คำนาม\" ต้องใช้คำนามรูปพหูพจน์เสมอ (เพราะหมายถึง 'หนึ่งในกลุ่มของหลายคน')","ส่วน (B) \"talented player\" ใช้คำนามเอกพจน์ ซึ่งผิดหลักไวยากรณ์","ต้องแก้เป็น \"talented players\" (รูปพหูพจน์)"],"tip":"โครงสร้าง \"one of the + superlative + plural noun\" (one of the best players, one of the most famous cities) ต้องใช้คำนามพหูพจน์เสมอ แม้ประธานหลักจะเป็นเอกพจน์ (He is one of...) ก็ตาม"},{"q":"I have (A)lived here (B)since (C)ten years (D)now. ส่วนใดผิดหลักไวยากรณ์","choices":["(A)","(B)","(C)","(D)"],"correct":1,"hint":"เปรียบเทียบ \"since\" กับ \"for\" — คำไหนใช้กับระยะเวลา (ten years) และคำไหนใช้กับจุดเริ่มต้น","steps":["\"ten years\" เป็นระยะเวลา (duration) ไม่ใช่จุดเริ่มต้นของเวลา","\"since\" ใช้กับจุดเริ่มต้นของเวลาเท่านั้น (since 2019, since Monday) ไม่ใช่ระยะเวลา","ส่วน (B) \"since\" จึงผิด ต้องแก้เป็น \"for\" (for ten years)"],"tip":"นี่คือจุดผิดที่พบบ่อยที่สุดในโจทย์ error identification — for+ระยะเวลา, since+จุดเริ่มต้น สลับกันไม่ได้เด็ดขาด"},{"q":"Neither of the students (A)have finished (B)their (C)homework (D)yet. ส่วนใดผิดหลักไวยากรณ์","choices":["(A)","(B)","(C)","(D)"],"correct":0,"hint":"\"Neither of\" ตามด้วยคำนามพหูพจน์ แต่ตัว \"Neither\" เองถือเป็นประธานเอกพจน์เมื่อผันกริยา","steps":["\"Neither of the students\" แม้จะตามด้วยคำนามพหูพจน์ (students) แต่ \"neither\" เป็นประธานเอกพจน์ตามหลักไวยากรณ์ทางการ","กริยาที่สอดคล้องกับประธานเอกพจน์คือ \"has\" ไม่ใช่ \"have\"","ส่วน (A) \"have finished\" จึงผิด ต้องแก้เป็น \"has finished\""],"tip":"คำว่า Neither, Either, Each, Every แม้ดูเหมือนพูดถึงคนหลายคน แต่ถือเป็นประธานเอกพจน์เสมอเมื่อผันกริยา เป็นกฎที่มักถูกมองข้าม"}]},
  {"id":"q_alevel_eng_headline","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเลือกพาดหัวข่าว","topic":"ทักษะการอ่าน (Best Headline Selection)","difficulty":"ยาก","intro":{"concept":"โจทย์เลือกพาดหัวข่าวที่ดีที่สุด (best headline) พบจริงในข้อสอบ A-Level อังกฤษ วัดทักษะจับใจความสำคัญของทั้งย่อหน้า ไม่ใช่แค่รายละเอียดเดียว — คำตอบที่ถูกต้องต้องครอบคลุมประเด็นหลักพอดี ไม่แคบเกินไป (จับแค่รายละเอียดย่อย) และไม่กว้าง/เกินจริงเกินไป (พูดเกินสิ่งที่บทความบอก)","worked":{"q":"Passage: \"Remote-controlled aircraft without human pilots are being developed by several airlines to cut costs. Supporters say the technology could save billions of pounds, but many passengers say they would not feel safe flying without a pilot on board.\" Question: What would be the best headline for this article?","steps":["บทความพูดถึง 2 ด้าน: การพัฒนาเทคโนโลยี (ประหยัดเงิน) และความกังวลของผู้โดยสาร (ความปลอดภัย)","หัวข้อที่ดีที่สุดต้องครอบคลุมทั้งสองด้าน ไม่ใช่แค่ด้านเดียว","'Remote Controlled Aircraft Coming But Not Everyone Approves' ครอบคลุมทั้งการมาถึงของเทคโนโลยีและความกังวลพร้อมกัน"],"answer":"Remote Controlled Aircraft Coming But Not Everyone Approves"}},"questions":[{"q":"Passage: \"A growing number of students are using AI chatbots to help with homework and exam preparation. While some teachers worry this could reduce critical thinking skills, many students report better understanding of difficult topics. Schools are now debating whether to embrace or restrict this technology.\" Question: What would be the best headline for this article?","choices":["Students Get Better Grades With AI","Schools Debate AI Use in Education as Students Embrace New Study Tool","AI Chatbots Replace Teachers Completely","Critical Thinking Skills Declining Nationwide"],"correct":1,"hint":"หาหัวข้อที่ครอบคลุมทั้งการใช้งานของนักเรียนและการถกเถียงของโรงเรียน ไม่ใช่แค่ด้านใดด้านหนึ่ง","steps":["ตัวเลือกที่ 1 พูดถึง 'เกรดดีขึ้น' ซึ่งบทความไม่ได้กล่าวถึงเลย","ตัวเลือกที่ 3 พูดเกินจริง (บทความไม่ได้บอกว่า AI แทนที่ครูทั้งหมด)","ตัวเลือกที่ 4 แคบเกินไป (พูดแค่ความกังวลด้านเดียว ไม่ครอบคลุมมุมมองนักเรียน)","ตัวเลือกที่ 2 ครอบคลุมทั้งการใช้งานจริงของนักเรียนและการถกเถียงของโรงเรียน จึงเป็นหัวข้อที่ดีที่สุด"],"tip":"ตัดตัวเลือกที่ 'แคบเกินไป' (จับแค่รายละเอียดเดียว) และ 'กว้าง/เกินจริงเกินไป' (พูดเกินสิ่งที่บทความบอกจริง) ออกก่อน จะเหลือคำตอบที่สมดุลพอดี"},{"q":"Passage: \"TechCorp announced this week that all employees must return to the office three days per week starting next month, reversing its fully remote policy from 2021. The company cited reduced collaboration and innovation as reasons, though some employees have expressed frustration over the change.\" Question: What would be the best headline for this article?","choices":["TechCorp Employees Quit Over New Rules","TechCorp Ends Fully Remote Work, Requires Office Days","Remote Work is Dead Everywhere","TechCorp Innovates With New Technology"],"correct":1,"hint":"หาหัวข้อที่ตรงกับข้อเท็จจริงหลักของข่าวพอดี ไม่ใช่การคาดเดาหรือขยายความเกินไปจากสิ่งที่ระบุจริง","steps":["ตัวเลือกที่ 1 คาดเดาเกินจริง (บทความบอกแค่ว่าพนักงาน 'ไม่พอใจ' ไม่ได้บอกว่า 'ลาออก')","ตัวเลือกที่ 3 กว้างเกินไป (บทความพูดถึงแค่บริษัทเดียว ไม่ใช่ทุกที่)","ตัวเลือกที่ 4 ผิดประเด็น (บทความไม่ได้พูดถึงเทคโนโลยีใหม่)","ตัวเลือกที่ 2 ตรงกับข้อเท็จจริงหลักพอดี: บริษัทยกเลิกนโยบายทำงานทางไกล ให้กลับเข้าออฟฟิศ"],"tip":"ระวังตัวเลือกที่ 'คาดเดาเกินสิ่งที่บทความบอกจริง' (เช่น จากความไม่พอใจ กลายเป็นการลาออก) เป็นกับดักที่พบบ่อยที่สุดในโจทย์แนวนี้"},{"q":"Passage: \"After years of neglect, the city's Central Park has undergone a $2 million renovation, adding new walking trails, a redesigned playground, and improved lighting for safety. The project, completed ahead of schedule, is expected to increase park visits by 40%.\" Question: What would be the best headline for this article?","choices":["City Spends Too Much on Park Renovation","Central Park Reopens After $2 Million Makeover","Playground Equipment Recalled for Safety","City Officials Predict Population Growth"],"correct":1,"hint":"หาหัวข้อที่เป็นกลาง สรุปข้อเท็จจริงหลักของข่าว ไม่ใช่ความคิดเห็นที่บทความไม่ได้ระบุ","steps":["ตัวเลือกที่ 1 เป็นความเห็นเชิงลบที่บทความไม่ได้ระบุ (ไม่มีใครในบทความบอกว่าใช้เงินมากเกินไป)","ตัวเลือกที่ 3 ผิดประเด็น (บทความไม่ได้พูดถึงการเรียกคืนอุปกรณ์)","ตัวเลือกที่ 4 ผิดประเด็น (บทความพูดถึงยอดผู้ใช้สวน ไม่ใช่การเติบโตของประชากรเมือง)","ตัวเลือกที่ 2 สรุปข้อเท็จจริงหลักอย่างเป็นกลาง: สวนกลับมาเปิดหลังปรับปรุงมูลค่า 2 ล้านดอลลาร์"],"tip":"หัวข้อข่าวที่ดีมักเป็นกลาง (neutral) ไม่ใส่ความคิดเห็น ถ้าตัวเลือกมีน้ำเสียงตัดสิน (ดีเกินไป/แย่เกินไป) ให้สงสัยไว้ก่อนว่าอาจไม่ใช่คำตอบ"},{"q":"Passage: \"A new study published this month found that people who read for at least 30 minutes daily showed improved memory and reduced stress levels compared to non-readers. Researchers tracked 500 participants over six months and controlled for factors like age and occupation.\" Question: What would be the best headline for this article?","choices":["Reading Books is the Only Way to Reduce Stress","Study Links Daily Reading to Better Memory and Lower Stress","500 People Participate in Memory Competition","Researchers Discover Cure for Stress"],"correct":1,"hint":"ระวังคำที่แสดงการพูดเกินจริงในตัวเลือก เช่น 'the only way' หรือ 'cure' ซึ่งเป็นคำที่หนักแน่นเกินกว่าสิ่งที่งานวิจัยบอกจริง","steps":["ตัวเลือกที่ 1 พูดเกินจริงด้วยคำว่า 'the only way' (บทความไม่ได้บอกว่าเป็นวิธีเดียว)","ตัวเลือกที่ 3 ผิดประเด็น (ไม่ใช่การแข่งขัน เป็นการศึกษาวิจัย)","ตัวเลือกที่ 4 พูดเกินจริงด้วยคำว่า 'cure' (การศึกษาพบ 'ความเชื่อมโยง' ไม่ใช่ 'วิธีรักษา')","ตัวเลือกที่ 2 สรุปผลการศึกษาอย่างถูกต้องและระมัดระวัง: เชื่อมโยงการอ่านกับความจำที่ดีขึ้นและความเครียดที่ลดลง"],"tip":"คำที่บ่งบอกการพูดเกินจริง (the only, always, never, cure, guarantee) มักเป็นสัญญาณของตัวเลือกที่ผิด งานวิจัยจริงมักใช้คำระมัดระวังกว่านี้ เช่น 'linked to', 'associated with'"}]},
  {"id":"q_alevel_eng_9","subjectId":"alevel-eng","title":"A-Level อังกฤษ · ไวยากรณ์และคำศัพท์พื้นฐาน ชุดที่ 2","topic":"ไวยากรณ์และคำศัพท์พื้นฐาน","difficulty":"กลาง","intro":{"concept":"ต่อยอดจากชุดแรก (Present Simple, past tense ผิดปกติ, คำเหมือน, for/since) มาเป็นการเปรียบเทียบขั้นกว่า (comparative), กริยาช่วยแสดงความจำเป็น (modal verbs), คำตรงข้าม (antonym), และ Present Continuous สำหรับเหตุการณ์ที่กำลังเกิดขึ้น","worked":{"q":"Choose the correct word: This book is ___ than that one.","steps":["ประโยคนี้เปรียบเทียบสิ่งของสองอย่าง (this book กับ that one) จึงต้องใช้รูปเปรียบเทียบขั้นกว่า (comparative)","คำคุณศัพท์ยาว (interesting) ต้องเติม 'more' ข้างหน้า ไม่ใช่เติม -er ต่อท้าย","รูปที่ถูกต้องคือ 'more interesting'"],"answer":"more interesting"}},"questions":[{"q":"Choose the correct word: This book is ___ than that one.","choices":["interesting","more interesting","most interesting","interestinger"],"correct":1,"hint":"คำคุณศัพท์ที่มีพยางค์ยาว (3 พยางค์ขึ้นไป) ต้องเติม 'more' ข้างหน้า ไม่เติม -er ต่อท้าย","steps":["ประโยคนี้เปรียบเทียบสองสิ่ง ('this book' กับ 'that one') จึงต้องใช้รูปเปรียบเทียบขั้นกว่า","'interesting' เป็นคำยาว (3 พยางค์) จึงใช้ 'more' นำหน้าแทนการเติม -er","รูปที่ถูกต้องคือ 'more interesting'"],"tip":"กฎทั่วไป: คำสั้น (1-2 พยางค์) เติม -er เช่น taller, bigger — คำยาว (3 พยางค์ขึ้นไป) ใช้ 'more' นำหน้า เช่น more expensive, more interesting"},{"q":"Choose the correct modal: You ___ see a doctor if you feel sick.","choices":["can","should","might","would"],"correct":1,"hint":"ประโยคนี้ให้คำแนะนำ ไม่ใช่แค่บอกความเป็นไปได้หรือความสามารถ","steps":["'can' แสดงความสามารถ, 'might' แสดงความเป็นไปได้ (ไม่แน่นอน), 'would' ใช้ในประโยคสมมติ","ประโยคนี้ต้องการให้คำแนะนำ (advice) ว่าควรทำอะไรเมื่อรู้สึกไม่สบาย","'should' คือกริยาช่วยที่ใช้แสดงคำแนะนำ จึงเป็นคำตอบที่ถูกต้อง"],"tip":"'should' ใช้ให้คำแนะนำ (advice) ต่างจาก 'must' ที่ใช้แสดงข้อบังคับที่หนักแน่นกว่ามาก (ต้องทำ ไม่ทำไม่ได้) ให้แยกความหนักเบาของกริยาช่วยแต่ละตัวให้ออก"},{"q":"Choose the word that means the opposite of 'expensive'.","choices":["costly","cheap","valuable","rare"],"correct":1,"hint":"หาคำที่มีความหมายตรงข้ามกับ 'ราคาแพง'","steps":["'expensive' หมายถึงราคาแพง","'costly' และ 'valuable' มีความหมายใกล้เคียงกับ 'expensive' ไม่ใช่ตรงข้าม","'cheap' หมายถึงราคาถูก เป็นคำตรงข้ามที่ถูกต้อง"],"tip":"ระวังตัวเลือกที่เป็นคำเหมือน (costly, valuable) ปนมากับคำตรงข้ามที่ถูกต้อง (cheap) — อ่านความหมายของทุกตัวเลือกให้ครบก่อนตัดสินใจเสมอ"},{"q":"Choose the correct word: Look! It ___ (rain) outside right now.","choices":["rains","rained","is raining","has rained"],"correct":2,"hint":"คำว่า 'Look!' และ 'right now' บ่งบอกเหตุการณ์ที่กำลังเกิดขึ้น ณ ขณะที่พูด","steps":["'Look!' และ 'right now' เป็นสัญญาณของเหตุการณ์ที่กำลังเกิดขึ้นตอนนี้พอดี","โครงสร้างที่ใช้กับเหตุการณ์ที่กำลังเกิดขึ้นคือ Present Continuous: is/am/are + กริยาเติม -ing","'is raining' จึงเป็นรูปที่ถูกต้อง ไม่ใช่ 'rains' (Present Simple ใช้กับเหตุการณ์ประจำ)"],"tip":"คำสัญญาณอย่าง 'Look!', 'Listen!', 'right now', 'at the moment' บ่งบอกว่าต้องใช้ Present Continuous ไม่ใช่ Present Simple แม้แต่กริยาที่ปกติมักเจอในรูป Simple ก็ตาม"}]},
  {"id":"q_alevel_eng_10","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านจับใจความ ชุดที่ 2","topic":"การอ่านจับใจความ","difficulty":"กลาง","intro":{"concept":"ต่อยอดจากชุดแรก (คนขับแท็กซี่, พยาบาล) ด้วยเนื้อเรื่องใหม่เกี่ยวกับคนขายดอกไม้ — เทคนิคยังเหมือนเดิม: จับคำสำคัญในคำถามแล้วสแกนหาในเนื้อเรื่อง ไม่ต้องแปลทุกคำ","worked":{"q":"Passage: \"Malee sells flowers at the morning market. She arrives at 5 a.m. to set up her stall.\" Question: What does Malee sell?","steps":["คำสำคัญในคำถามคือ 'sell'","ประโยคแรกระบุตรงๆ ว่า 'Malee sells flowers'","คำตอบคือ flowers (ดอกไม้)"],"answer":"Flowers"}},"questions":[{"q":"Passage: \"Malee sells flowers at the morning market. She arrives at 5 a.m. to set up her stall. Her favorite flowers to sell are roses because they smell nice. She closes her stall at noon and goes home to rest.\" Question: What does Malee sell?","choices":["Flowers","Fruit","Vegetables","Fish"],"correct":0,"hint":"เนื้อเรื่องบอกสิ่งที่เธอขายตรงๆ ในประโยคแรก","steps":["คำสำคัญในคำถามคือ 'sell'","ประโยคแรกระบุตรงๆ ว่า 'Malee sells flowers'","คำตอบคือ Flowers"],"tip":"คำถามถามสิ่งที่ขายมักตอบได้จากประโยคที่มีคำว่า 'sells...' ตรงๆ ในตอนต้นเรื่อง"},{"q":"Passage เดียวกับข้อก่อนหน้า: What time does Malee arrive at the market?","choices":["5 a.m.","6 a.m.","7 a.m.","Noon"],"correct":0,"hint":"หาตัวเลขเวลาที่ปรากฏในเนื้อเรื่องตรงๆ ระวังอย่าสับสนกับเวลาปิดร้าน","steps":["คำสำคัญในคำถามคือ 'arrive' และ 'what time'","เนื้อเรื่องระบุว่า 'She arrives at 5 a.m.'","คำตอบคือ 5 a.m. (ไม่ใช่ noon ซึ่งเป็นเวลาปิดแผง)"],"tip":"ระวังตัวเลือกที่เป็นเวลาอื่นที่ปรากฏในเนื้อเรื่องเช่นกัน (noon เป็นเวลาปิด ไม่ใช่เวลามาถึง) ต้องจับคู่เวลากับคำสำคัญในคำถามให้ตรงจุด"},{"q":"Passage เดียวกับข้อก่อนหน้า: What are Malee's favorite flowers to sell?","choices":["Roses","Tulips","Sunflowers","Orchids"],"correct":0,"hint":"หาคำที่เกี่ยวกับดอกไม้โปรดในเนื้อเรื่อง","steps":["คำสำคัญในคำถามคือ 'favorite flowers'","เนื้อเรื่องระบุว่า 'Her favorite flowers to sell are roses'","คำตอบคือ Roses"],"tip":"คำถามถามสิ่งที่ 'favorite' มักตอบได้จากประโยคที่มีคำนี้ตรงๆ"},{"q":"Passage เดียวกับข้อก่อนหน้า: What time does Malee close her stall?","choices":["Noon","5 a.m.","6 p.m.","9 a.m."],"correct":0,"hint":"หาประโยคสุดท้ายของเนื้อเรื่องที่พูดถึงการปิดแผง","steps":["คำสำคัญในคำถามคือ 'close' และ 'what time'","เนื้อเรื่องระบุว่า 'She closes her stall at noon'","คำตอบคือ Noon"],"tip":"เมื่อเนื้อเรื่องมีเวลาหลายจุด (มาถึง 5 โมงเช้า, ปิดตอนเที่ยง) ต้องอ่านทั้งประโยคให้ครบว่าเวลานั้นคู่กับกิจกรรมอะไร ไม่ใช่จับตัวเลขแรกที่เจอ"}]},
  {"id":"q_alevel_eng_11","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเติมข้อความให้สมบูรณ์ ชุดที่ 2","topic":"ทักษะการเขียน (Text Completion)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (by/until, although, which แทนทั้งประโยค, not only...but also) มาเป็นคำเชื่อมใหม่: as soon as (ทันทีที่), in order to (เพื่อที่จะ), even though (แม้ว่า), unless (เว้นแต่)","worked":{"q":"___ the alarm rang, everyone left the building right away.","steps":["ประโยคนี้บ่งบอกลำดับเหตุการณ์ที่เกิดขึ้นทันทีต่อเนื่องกัน (สัญญาณเตือน→ออกจากอาคารทันที)","'As soon as' หมายถึง 'ทันทีที่' ใช้เชื่อมเหตุการณ์สองอย่างที่เกิดต่อเนื่องกันแทบจะพร้อมกัน","คำเชื่อมอื่น (Although, Unless, While) ไม่ตรงกับความหมายลำดับเวลาแบบทันทีนี้"],"answer":"As soon as"}},"questions":[{"q":"___ the alarm rang, everyone left the building right away.","choices":["As soon as","Although","Unless","While"],"correct":0,"hint":"หาคำเชื่อมที่แสดงลำดับเวลาแบบ 'ทันทีที่เกิดเหตุการณ์หนึ่ง อีกเหตุการณ์หนึ่งก็ตามมาทันที'","steps":["ประโยคนี้บ่งบอกว่าสองเหตุการณ์เกิดต่อเนื่องกันแทบจะทันที","'As soon as' แปลว่า 'ทันทีที่' ตรงกับความหมายนี้พอดี","คำเชื่อมอื่นแสดงความขัดแย้ง (Although) เงื่อนไข (Unless) หรือเหตุการณ์คู่ขนาน (While) ไม่ตรงบริบท"],"tip":"'As soon as' เป็นคำเชื่อมเวลาที่เน้นความทันทีทันใดของเหตุการณ์ที่สอง มักมาคู่กับคำอย่าง 'right away', 'immediately' ในประโยคหลัก"},{"q":"She is studying hard ___ pass the entrance exam.","choices":["in order to","so that","because of","despite"],"correct":0,"hint":"ช่องว่างตามด้วยกริยาช่องที่ 1 โดยตรง ('pass') ไม่ใช่ประโยคที่มีประธาน+กริยา","steps":["'in order to' ตามด้วยกริยาช่องที่ 1 โดยตรงเพื่อแสดงจุดประสงค์ (purpose)","'so that' ต้องตามด้วยประโยคที่มีประธาน (so that she can pass) ไม่ใช่กริยาเปล่าๆ","'because of' และ 'despite' ตามด้วยคำนาม ไม่ใช่กริยา จึงไม่เข้ากับโครงสร้างนี้"],"tip":"'in order to + กริยาช่องที่ 1' และ 'so that + ประโยค' ทั้งคู่แสดงจุดประสงค์ได้เหมือนกัน แต่โครงสร้างตามหลังต่างกัน ต้องดูว่าตามด้วยกริยาเปล่าหรือประโยคเต็ม"},{"q":"___ it was raining, they still went out for a walk.","choices":["Even though","Because","So","If"],"correct":0,"hint":"ประโยคนี้มีความขัดแย้งกัน (ฝนตกแต่ยังออกไปเดินเล่น) หาคำเชื่อมที่แสดงความขัดแย้ง","steps":["สังเกตความขัดแย้งระหว่างสองเหตุการณ์: ฝนตก กับ ยังออกไปเดินเล่น","'Even though' แสดงความขัดแย้ง (แม้ว่า...ก็ยัง...) ตรงกับความหมายนี้","'Because' แสดงเหตุผล 'So' แสดงผลลัพธ์ 'If' แสดงเงื่อนไข ไม่ตรงกับความขัดแย้งในประโยค"],"tip":"'Even though' มีความหมายเหมือน 'Although' ใช้แทนกันได้ในบริบทนี้ ทั้งคู่แสดงความขัดแย้งระหว่างสองเหตุการณ์"},{"q":"You won't succeed ___ you try harder.","choices":["unless","if","because","so"],"correct":0,"hint":"ประโยคนี้มีความหมายว่า 'จะสำเร็จได้ก็ต่อเมื่อพยายามมากขึ้นเท่านั้น' หาคำเชื่อมที่ตรงกับเงื่อนไขเชิงลบนี้","steps":["'unless' มีความหมายเทียบเท่า 'if...not' (ถ้าไม่...)","'You won't succeed unless you try harder' = 'You will succeed only if you try harder'","คำเชื่อมอื่น (if, because, so) ไม่ได้ให้ความหมายเงื่อนไขเชิงลบแบบนี้"],"tip":"'unless' มักสร้างความสับสนเพราะมีความหมายเชิงลบซ่อนอยู่ (=if...not) ลองแปลงประโยคเป็น 'if...not' เพื่อเช็คความหมายให้แน่ใจก่อนเลือกคำตอบ"}]},
  {"id":"q_alevel_eng_12","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเรียงลำดับประโยค ชุดที่ 2","topic":"ทักษะการเขียน (Paragraph/Sentence Ordering)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (ทริปทะเลที่ฝนตก, อบคุกกี้, พลังงานหมุนเวียน, ชีวประวัติ Malee) ด้วยย่อหน้าใหม่ 4 แบบ: การสมัครงาน, การชงชา, เหตุ-ผลเรื่องมลพิษ, เรื่องเล่าสุนัขหาย — เทคนิคเดิม: สังเกตคำเชื่อมบอกลำดับ/เหตุผล","worked":{"q":"เรียงลำดับให้ถูกต้อง: (A) After that, I searched online for job openings that matched my skills. (B) First, I updated my resume with my latest experience. (C) Finally, I received an interview invitation from my first-choice company. (D) Then, I submitted applications to five different companies.","steps":["สังเกตคำเชื่อมบอกลำดับในแต่ละประโยค: First(B), After that(A), Then(D), Finally(C)","คำเหล่านี้บ่งบอกลำดับขั้นตอนอย่างชัดเจนตามลำดับ First→After that→Then→Finally","จัดเรียงตามลำดับคำเชื่อม: B-A-D-C"],"answer":"B-A-D-C"}},"questions":[{"q":"เรียงลำดับประโยคเกี่ยวกับการสมัครงานให้ถูกต้อง: (A) After that, I searched online for job openings that matched my skills. (B) First, I updated my resume with my latest experience. (C) Finally, I received an interview invitation from my first-choice company. (D) Then, I submitted applications to five different companies.","choices":["B-A-D-C","A-B-C-D","B-D-A-C","A-B-D-C"],"correct":0,"hint":"หาคำเชื่อมบอกลำดับในแต่ละประโยค (First, After that, Then, Finally) แล้วจัดเรียงตามนั้น","steps":["'First' (B) ต้องมาก่อนเสมอ — ปรับปรุงเรซูเม่","'After that' (A) ตามมาเป็นลำดับที่สอง — หางานออนไลน์","'Then' (D) ตามมาเป็นลำดับที่สาม — ส่งใบสมัคร","'Finally' (C) ปิดท้าย — ได้รับคำเชิญสัมภาษณ์ — ลำดับที่ถูกต้องคือ B-A-D-C"],"tip":"คำเชื่อมลำดับ (First, After that, Then, Finally) เป็นตัวช่วยจัดเรียงที่ชัดเจนที่สุด ไม่ต้องตีความเนื้อหาลึกก็จัดลำดับได้ถูกต้อง"},{"q":"เรียงลำดับขั้นตอนการชงชาให้ถูกต้อง: (A) Then, add the tea leaves. (B) Finally, pour the tea into a cup. (C) First, boil the water. (D) Next, let it steep for 3 minutes.","choices":["C-A-D-B","A-C-D-B","C-D-A-B","A-B-C-D"],"correct":0,"hint":"หาคำเชื่อมบอกลำดับ (First, Then, Next, Finally) แล้วจัดเรียงตามนั้น","steps":["'First' (C) ต้องมาก่อนเสมอ — ต้มน้ำ","'Then' (A) ตามมา — ใส่ใบชา","'Next' (D) ตามมา — แช่ทิ้งไว้ 3 นาที","'Finally' (B) ปิดท้าย — เทชาใส่ถ้วย — ลำดับที่ถูกต้องคือ C-A-D-B"],"tip":"ขั้นตอนการทำอาหาร/เครื่องดื่มมักมีคำเชื่อมลำดับครบชุด (First, Then/Next, Finally) ให้จับคำเหล่านี้เป็นหลักในการจัดเรียง"},{"q":"เรียงลำดับประโยคเกี่ยวกับมลพิษทางอากาศให้เป็นย่อหน้าเหตุ-ผลที่สมเหตุสมผล: (A) Because of this, the government has introduced new regulations. (B) Air pollution has increased in the city. (C) These regulations aim to reduce emissions from factories. (D) As a result, more people are experiencing breathing problems.","choices":["B-D-A-C","B-A-D-C","A-B-D-C","D-B-A-C"],"correct":0,"hint":"เริ่มจากสาเหตุตั้งต้น (มลพิษเพิ่มขึ้น) แล้วตามด้วยผลกระทบ แล้วตามด้วยมาตรการแก้ไข","steps":["ประโยคที่เป็นสาเหตุตั้งต้นควรมาก่อน คือ (B) มลพิษทางอากาศเพิ่มขึ้น","ตามด้วย (D) 'As a result' ผลกระทบโดยตรง — ปัญหาระบบทางเดินหายใจ","ตามด้วย (A) 'Because of this' มาตรการที่ตามมา — รัฐบาลออกกฎระเบียบใหม่","ปิดท้ายด้วย (C) รายละเอียดของกฎระเบียบนั้น — ลำดับที่ถูกต้องคือ B-D-A-C"],"tip":"ย่อหน้าแบบเหตุ-ผลมักมีโครงสร้าง: สาเหตุตั้งต้น → ผลกระทบ (as a result) → มาตรการรับมือ (because of this) → รายละเอียดมาตรการ ให้ไล่ตามโครงสร้างนี้"},{"q":"เรียงลำดับเรื่องราวเกี่ยวกับสุนัขหายให้ถูกต้อง: (A) He searched the neighborhood for hours without success. (B) Tom was overjoyed and thanked her repeatedly. (C) Tom's dog ran away during a thunderstorm. (D) Finally, a neighbor called to say she had found the dog.","choices":["C-A-D-B","C-D-A-B","A-C-D-B","C-A-B-D"],"correct":0,"hint":"นี่คือลำดับเหตุการณ์ตามเวลา (chronological order) เริ่มจากต้นเหตุของเรื่อง","steps":["เหตุการณ์แรกสุดคือ (C) สุนัขของทอมวิ่งหายไปตอนพายุฝนฟ้าคะนอง","ตามด้วย (A) เขาค้นหาในละแวกบ้านหลายชั่วโมงแต่ไม่พบ","ตามด้วย (D) 'Finally' เพื่อนบ้านโทรมาบอกว่าพบสุนัขแล้ว","ปิดท้ายด้วย (B) ทอมดีใจมากและขอบคุณเธอซ้ำๆ — ลำดับที่ถูกต้องคือ C-A-D-B"],"tip":"เรื่องเล่าที่มีจุดวิกฤต (สุนัขหาย) มักเรียงตามโครงสร้าง: จุดเริ่มปัญหา → ความพยายามแก้ไข → จุดพลิกผัน (finally) → ผลลัพธ์/ความรู้สึก"}]},
  {"id":"q_alevel_eng_13","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านโฆษณาและรีวิว ชุดที่ 2","topic":"ทักษะการอ่าน (Advertisement & Review)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (โฆษณารองเท้า, รีวิวร้านอาหาร) ด้วยโฆษณายิมและรีวิวหูฟังไร้สาย — เทคนิคเดิม: แยกให้ออกระหว่างข้อเท็จจริงที่ระบุตรงๆ กับสิ่งที่ผู้อ่านต้องตีความเอง","worked":{"q":"Advertisement: \"GRAND OPENING! FitZone Gym is now open. Sign up before July 31 and get your first month FREE!\" Question: What do new members get if they sign up before July 31?","steps":["คำสำคัญในคำถามคือ 'before July 31' และ 'get'","โฆษณาระบุตรงๆ ว่า 'get your first month FREE'","คำตอบคือ เดือนแรกฟรี (first month free)"],"answer":"Their first month free"}},"questions":[{"q":"Advertisement: \"GRAND OPENING! FitZone Gym is now open. Sign up before July 31 and get your first month FREE! Includes access to pool, sauna, and group classes. Located at 456 Park Avenue. Call 02-123-4567 for more info.\" Question: What do new members get if they sign up before July 31?","choices":["Their first month free","A free gym bag","A free t-shirt","Half-price membership"],"correct":0,"hint":"หาข้อเสนอที่ระบุตรงๆ ในโฆษณาเกี่ยวกับวันที่ 31 กรกฎาคม","steps":["คำสำคัญในคำถามคือ 'before July 31' และ 'get'","โฆษณาระบุตรงๆ ว่า 'Sign up before July 31 and get your first month FREE'","คำตอบคือ Their first month free"],"tip":"โฆษณามักมีข้อเสนอผูกกับวันที่กำหนด (deadline) ให้จับคู่วันที่กับข้อเสนอที่ตามมาในประโยคเดียวกันเสมอ"},{"q":"Advertisement เดียวกับข้อก่อนหน้า: What facilities are included in the FitZone Gym membership?","choices":["Pool, sauna, and group classes","Only a swimming pool","A restaurant and a cafe","Personal training sessions only"],"correct":0,"hint":"หารายการสิ่งอำนวยความสะดวกที่ระบุในโฆษณา","steps":["คำสำคัญในคำถามคือ 'facilities' และ 'included'","โฆษณาระบุว่า 'Includes access to pool, sauna, and group classes'","คำตอบคือ Pool, sauna, and group classes"],"tip":"คำถามถามรายการสิ่งของ/บริการ มักตอบได้จากประโยคที่มีคำว่า 'includes' ตรงๆ ต้องอ่านให้ครบทุกรายการที่ระบุ ไม่ใช่แค่รายการแรก"},{"q":"Advertisement เดียวกับข้อก่อนหน้า: Where is FitZone Gym located?","choices":["456 Park Avenue","123 Main Street","789 River Road","100 Center Street"],"correct":0,"hint":"หาที่อยู่ที่ระบุในโฆษณาตรงๆ","steps":["คำสำคัญในคำถามคือ 'located'","โฆษณาระบุตรงๆ ว่า 'Located at 456 Park Avenue'","คำตอบคือ 456 Park Avenue"],"tip":"โฆษณามักมีที่อยู่ระบุตรงๆ ใกล้กับเบอร์โทรศัพท์ติดต่อ ให้สแกนหาคำว่า 'Located at' หรือ 'at' ตามด้วยที่อยู่"},{"q":"Review: \"I bought these wireless headphones last week. The sound quality is excellent, and the battery lasts all day. However, they are a bit uncomfortable after wearing them for more than two hours.\" Question: According to the review, what does the reviewer dislike about the headphones?","choices":["They are uncomfortable after wearing them for a long time","The sound quality is poor","The battery doesn't last long","They are too expensive"],"correct":0,"hint":"หาคำว่า 'However' ในรีวิว ซึ่งมักนำหน้าข้อเสียหรือข้อบกพร่อง","steps":["คำว่า 'However' บ่งบอกว่าประโยคที่ตามมาเป็นมุมมองที่ตรงข้ามกับที่กล่าวมาก่อนหน้า (ซึ่งเป็นข้อดี)","รีวิวระบุว่า 'they are a bit uncomfortable after wearing them for more than two hours'","คำตอบคือ ไม่สบายเมื่อใส่นานเกิน 2 ชั่วโมง"],"tip":"คำว่า 'However', 'But', 'On the other hand' มักเป็นสัญญาณบอกจุดเปลี่ยนจากข้อดีไปข้อเสีย (หรือกลับกัน) ในรีวิว ให้จับคำเหล่านี้เป็นจุดสังเกตสำคัญ"}]},
  {"id":"q_alevel_eng_14","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านข่าวและบทความ ชุดที่ 2","topic":"ทักษะการอ่าน (News & Article)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (สวนสาธารณะกรุงเทพฯ, บทความออกกำลังกาย) ด้วยข่าวทุนการศึกษาและบทความเรื่องการนอนหลับ — เทคนิคเดิม: แยกข้อเท็จจริง (facts) ออกจากรายละเอียดสนับสนุน","worked":{"q":"News: \"Chiang Mai University announced a new scholarship program for students studying environmental science.\" Question: What subject is the new scholarship program for?","steps":["คำสำคัญในคำถามคือ 'subject' และ 'scholarship'","ข่าวระบุตรงๆ ว่า 'for students studying environmental science'","คำตอบคือ environmental science (วิทยาศาสตร์สิ่งแวดล้อม)"],"answer":"Environmental science"}},"questions":[{"q":"News: \"Chiang Mai University announced a new scholarship program for students studying environmental science. The program will provide full tuition coverage for 50 students starting next semester. Applications open on August 1.\" Question: What subject is the new scholarship program for?","choices":["Environmental science","Computer science","Business administration","Medicine"],"correct":0,"hint":"หาวิชาที่ระบุตรงๆ ในข่าว","steps":["คำสำคัญในคำถามคือ 'subject' และ 'scholarship'","ข่าวระบุตรงๆ ว่า 'for students studying environmental science'","คำตอบคือ Environmental science"],"tip":"คำถามถามหัวข้อ/สาขาวิชา มักตอบได้จากประโยคที่มีคำว่า 'for students studying...' หรือ 'in the field of...' ตรงๆ"},{"q":"News เดียวกับข้อก่อนหน้า: How many students will receive the scholarship?","choices":["50 students","100 students","25 students","10 students"],"correct":0,"hint":"หาตัวเลขจำนวนคนที่ระบุตรงๆ ในข่าว","steps":["คำสำคัญในคำถามคือ 'how many students'","ข่าวระบุตรงๆ ว่า 'for 50 students'","คำตอบคือ 50 students"],"tip":"คำถามถามจำนวน มักตอบได้จากตัวเลขที่ปรากฏตรงๆ ในเนื้อข่าว ให้สแกนหาตัวเลขก่อนเป็นอันดับแรก"},{"q":"News เดียวกับข้อก่อนหน้า: When do applications for the scholarship open?","choices":["August 1","July 1","September 1","June 1"],"correct":0,"hint":"หาวันที่ที่ระบุตรงๆ ในประโยคสุดท้ายของข่าว","steps":["คำสำคัญในคำถามคือ 'when' และ 'applications open'","ข่าวระบุตรงๆ ว่า 'Applications open on August 1'","คำตอบคือ August 1"],"tip":"ข่าวมักปิดท้ายด้วยข้อมูลวันที่สำคัญ (deadline, วันเปิดรับสมัคร) ให้ตรวจสอบประโยคสุดท้ายของข่าวเสมอเมื่อคำถามถามเรื่องวันที่"},{"q":"Article: \"Getting enough sleep is essential for both physical and mental health. Studies show that adults who sleep less than six hours a night are more likely to experience memory problems and weakened immune systems. Experts recommend 7-9 hours of sleep per night for optimal health.\" Question: According to the article, how many hours of sleep do experts recommend per night?","choices":["7-9 hours","4-6 hours","10-12 hours","5-7 hours"],"correct":0,"hint":"หาตัวเลขช่วงชั่วโมงที่ระบุตรงๆ ในประโยคสุดท้ายของบทความ","steps":["คำสำคัญในคำถามคือ 'experts recommend' และ 'how many hours'","บทความระบุตรงๆ ว่า 'Experts recommend 7-9 hours of sleep per night'","คำตอบคือ 7-9 hours"],"tip":"ระวังตัวเลือกที่เป็นตัวเลขอื่นที่ปรากฏในบทความเช่นกัน ('less than six hours' เป็นตัวอย่างของการนอนไม่พอ ไม่ใช่คำแนะนำของผู้เชี่ยวชาญ) ต้องจับคู่ตัวเลขกับคำสำคัญในคำถามให้ตรงจุด"}]},
  {"id":"q_alevel_eng_15","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การอ่านข้อมูลกราฟ/แผนภูมิ ชุดที่ 2","topic":"ทักษะการอ่าน (Graph/Chart Data)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (สำรวจวิชาโปรด, ยอดขายรายไตรมาส) ด้วยข้อมูลวิธีเดินทางมาทำงานและค่าใช้จ่ายครัวเรือน — เทคนิคเดิม: อ่านตัวเลขให้ครบก่อนคำนวณ และระวังหน่วยของแต่ละแกน/หมวดหมู่","worked":{"q":"Data: A survey of 200 commuters' transportation methods to work: Car - 80 people, Bus - 60 people, Motorcycle - 40 people, Walking - 20 people. Question: How many more people use cars than motorcycles to commute?","steps":["หาจำนวนคนที่ใช้รถยนต์: 80 คน","หาจำนวนคนที่ใช้มอเตอร์ไซค์: 40 คน","หาผลต่าง: 80−40 = 40 คน"],"answer":"40 people"}},"questions":[{"q":"Data: A survey of 200 commuters' transportation methods to work: Car - 80 people, Bus - 60 people, Motorcycle - 40 people, Walking - 20 people. Question: How many more people use cars than motorcycles to commute?","choices":["40 people","20 people","60 people","80 people"],"correct":0,"hint":"หาผลต่างระหว่างจำนวนคนที่ใช้รถยนต์กับมอเตอร์ไซค์","steps":["จำนวนคนที่ใช้รถยนต์ = 80 คน","จำนวนคนที่ใช้มอเตอร์ไซค์ = 40 คน","ผลต่าง = 80−40 = 40 คน"],"tip":"โจทย์ถาม 'how many more' ต้องคำนวณผลต่าง (การลบ) ไม่ใช่แค่บอกตัวเลขตัวใดตัวหนึ่งเฉยๆ"},{"q":"Data เดียวกับข้อก่อนหน้า: What percentage of commuters use the bus?","choices":["30%","20%","40%","60%"],"correct":0,"hint":"หาสัดส่วนของคนใช้รถบัสเทียบกับจำนวนคนทั้งหมด (200 คน) แล้วแปลงเป็นเปอร์เซ็นต์","steps":["จำนวนคนที่ใช้รถบัส = 60 คน จากทั้งหมด 200 คน","คำนวณสัดส่วน: 60/200 = 0.3","แปลงเป็นเปอร์เซ็นต์: 30%"],"tip":"โจทย์เปอร์เซ็นต์จากข้อมูลสำรวจ ต้องหารด้วย 'จำนวนรวมทั้งหมด' เสมอ (200 คน) ไม่ใช่หารด้วยตัวเลขหมวดอื่น"},{"q":"Data: Monthly household expenses: Rent - $800, Food - $400, Transportation - $200, Entertainment - $100. Total monthly expenses: $1,500. Question: According to the data, what is the largest monthly expense category?","choices":["Rent","Food","Transportation","Entertainment"],"correct":0,"hint":"เปรียบเทียบตัวเลขค่าใช้จ่ายทั้ง 4 หมวดหมู่ หาตัวที่มากที่สุด","steps":["เปรียบเทียบตัวเลข: Rent=$800, Food=$400, Transportation=$200, Entertainment=$100","$800 (Rent) เป็นตัวเลขที่มากที่สุดในบรรดาทั้ง 4 หมวด","คำตอบคือ Rent"],"tip":"โจทย์ถามค่าที่ 'มากที่สุด/น้อยที่สุด' ให้เปรียบเทียบตัวเลขทุกหมวดหมู่ให้ครบก่อนตอบ อย่าด่วนตอบจากหมวดแรกที่เห็น"},{"q":"Data เดียวกับข้อก่อนหน้า: What percentage of total monthly expenses is spent on food (rounded to the nearest whole number)?","choices":["27%","15%","50%","8%"],"correct":0,"hint":"หาสัดส่วนค่าอาหารเทียบกับค่าใช้จ่ายรวมทั้งหมด ($1,500) แล้วแปลงเป็นเปอร์เซ็นต์และปัดเศษ","steps":["ค่าอาหาร = $400 จากค่าใช้จ่ายรวม $1,500","คำนวณสัดส่วน: 400/1500 ≈ 0.267","แปลงเป็นเปอร์เซ็นต์และปัดเศษ: ≈ 27%"],"tip":"เมื่อโจทย์ให้ 'total' มาตรงๆ ($1,500) ให้ใช้ตัวเลขนั้นเป็นตัวหารเลย ไม่ต้องบวกตัวเลขย่อยเองใหม่ (ป้องกันการบวกผิดพลาด)"}]},
  {"id":"q_alevel_eng_16","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การหาข้อผิดพลาดในประโยค ชุดที่ 2","topic":"ทักษะการเขียน (Error Identification)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (subject-verb agreement กับ was/were, เอกพจน์-พหูพจน์ของคำนาม, since/for, neither...have) มาเป็นข้อผิดพลาดชนิดใหม่: 'each of' + กริยาเอกพจน์, 'the number of' + กริยาเอกพจน์, การซ้ำซ้อนของคำเปรียบเทียบขั้นกว่า (double comparative), และความสอดคล้องของ tense ใน past perfect","worked":{"q":"Each of the students (A)have submitted (B)their (C)assignment (D)on time. ส่วนใดผิด","steps":["'Each of + คำนามพหูพจน์' ทำหน้าที่เป็นประธานเอกพจน์เสมอ ต้องใช้กริยาเอกพจน์","'have submitted' เป็นกริยาพหูพจน์ ผิดหลักไวยากรณ์ ต้องเป็น 'has submitted'","คำตอบคือส่วน (A)"],"answer":"(A) — ต้องเป็น 'has submitted'"}},"questions":[{"q":"Each of the students (A)have submitted (B)their (C)assignment (D)on time. ส่วนใดผิด","choices":["A","B","C","D"],"correct":0,"hint":"'Each of + คำนามพหูพจน์' เป็นประธานเอกพจน์เสมอ ต้องใช้กริยาเอกพจน์คู่กัน","steps":["'Each of the students' แม้จะมี 'students' เป็นพหูพจน์ แต่ 'each' ทำให้ประธานทั้งวลีเป็นเอกพจน์","กริยาที่ถูกต้องคือ 'has submitted' ไม่ใช่ 'have submitted'","ส่วนที่ผิดคือ (A)"],"tip":"'each of', 'every one of' ตามด้วยคำนามพหูพจน์แต่ต้องใช้กริยาเอกพจน์เสมอ (each/every มีความหมายว่า 'ทีละคน' จึงนับเป็นเอกพจน์)"},{"q":"The number of tourists (A)have increased (B)significantly (C)over the past (D)decade. ส่วนใดผิด","choices":["A","B","C","D"],"correct":0,"hint":"เปรียบเทียบ 'The number of' (เอกพจน์) กับ 'A number of' (พหูพจน์) ให้ดี — สองวลีนี้ใช้กริยาต่างกัน","steps":["'The number of + คำนามพหูพจน์' หมายถึง 'จำนวนของ...' เป็นประธานเอกพจน์ (ตัวเลขจำนวนเดียว)","กริยาที่ถูกต้องคือ 'has increased' ไม่ใช่ 'have increased'","ส่วนที่ผิดคือ (A)"],"tip":"จำคู่นี้ให้แม่น: 'The number of' = เอกพจน์ (has/is), 'A number of' = พหูพจน์ (have/are) แม้หน้าตาจะคล้ายกันมากแต่ความหมายและไวยากรณ์ต่างกัน"},{"q":"My brother is (A)more taller (B)than me, but (C)he is (D)younger. ส่วนใดผิด","choices":["A","B","C","D"],"correct":0,"hint":"คำคุณศัพท์สั้นที่เติม -er แล้ว ไม่ต้องเติม 'more' นำหน้าซ้ำอีก","steps":["'taller' เป็นรูปเปรียบเทียบขั้นกว่าที่เติม -er แล้ว (คำสั้น 1 พยางค์)","การเติม 'more' นำหน้า 'taller' อีกเป็นการซ้ำซ้อน (double comparative) ซึ่งผิดไวยากรณ์","รูปที่ถูกต้องคือ 'taller' เฉยๆ ไม่ต้องมี 'more' — ส่วนที่ผิดคือ (A)"],"tip":"คำคุณศัพท์สั้น (1-2 พยางค์) เติม -er เท่านั้น ห้ามเติม 'more' นำหน้าซ้ำ — 'more taller', 'more bigger' เป็นข้อผิดพลาดที่พบบ่อยมาก"},{"q":"By the time we arrived, the movie (A)had already (B)starts (C)and we (D)missed the beginning. ส่วนใดผิด","choices":["A","B","C","D"],"correct":1,"hint":"โครงสร้าง past perfect ('had already') ต้องตามด้วยกริยาช่องที่ 3 ไม่ใช่กริยาเติม -s","steps":["'By the time we arrived' บ่งบอกว่าต้องใช้ past perfect สำหรับเหตุการณ์ที่เกิดก่อนหน้านั้น","'had already' ต้องตามด้วยกริยาช่องที่ 3 (past participle) เช่น 'started' ไม่ใช่ 'starts'","ส่วนที่ผิดคือ (B) ต้องแก้เป็น 'had already started'"],"tip":"'By the time + อดีต, ประธาน + had + กริยาช่องที่ 3' เป็นโครงสร้าง past perfect มาตรฐาน ระวังอย่าเผลอใช้กริยาเติม -s หรือรูปปัจจุบันปนเข้ามา"}]},
  {"id":"q_alevel_eng_headline2","subjectId":"alevel-eng","title":"A-Level อังกฤษ · การเลือกพาดหัวข่าว ชุดที่ 2","topic":"ทักษะการอ่าน (Best Headline Selection)","difficulty":"ยาก","intro":{"concept":"ต่อยอดจากชุดแรก (แชทบอท AI, TechCorp เรียกกลับออฟฟิศ, สวนสาธารณะ, การอ่านหนังสือ) ด้วยข่าวใหม่ 4 เรื่อง — เทคนิคเดิม: ตัดตัวเลือกที่แคบเกินไป กว้าง/เกินจริงเกินไป หรือผิดประเด็นออกก่อน","worked":{"q":"Passage: \"Local officials have proposed banning single-use plastic bags in all supermarkets starting next year. Environmental groups have praised the move, while some business owners worry about increased costs.\" Question: What would be the best headline for this article?","steps":["บทความพูดถึง 2 ด้าน: ข้อเสนอห้ามถุงพลาสติก และปฏิกิริยาที่หลากหลาย (กลุ่มสิ่งแวดล้อมชม, ผู้ประกอบการกังวล)","หัวข้อที่ดีที่สุดต้องครอบคลุมทั้งสองด้าน ไม่ใช่แค่ด้านเดียว","'City Proposes Plastic Bag Ban Amid Mixed Reactions' ครอบคลุมทั้งข้อเสนอและปฏิกิริยาที่หลากหลายพร้อมกัน"],"answer":"City Proposes Plastic Bag Ban Amid Mixed Reactions"}},"questions":[{"q":"Passage: \"Local officials have proposed banning single-use plastic bags in all supermarkets starting next year. Environmental groups have praised the move, while some business owners worry about increased costs. A public consultation period will begin next month.\" Question: What would be the best headline for this article?","choices":["City Proposes Plastic Bag Ban Amid Mixed Reactions","Businesses Worried About Costs","All Plastic Banned Forever Starting Today","Environmental Groups Celebrate Final Victory"],"correct":0,"hint":"หาหัวข้อที่ครอบคลุมทั้งข้อเสนอและปฏิกิริยาที่หลากหลาย ไม่ใช่แค่มุมมองเดียว","steps":["ตัวเลือกที่ 2 แคบเกินไป (จับแค่ความกังวลของผู้ประกอบการฝ่ายเดียว)","ตัวเลือกที่ 3 พูดเกินจริง (บทความบอกว่าเป็นแค่ 'ข้อเสนอ' ที่ยังอยู่ในช่วงรับฟังความเห็น ไม่ใช่ห้ามแล้วจริง)","ตัวเลือกที่ 4 พูดเกินจริงเช่นกัน (ยังเป็นแค่ข้อเสนอ ไม่ใช่ชัยชนะที่ตัดสินแล้ว)","ตัวเลือกที่ 1 ครอบคลุมทั้งข้อเสนอและปฏิกิริยาที่หลากหลายอย่างสมดุล จึงเป็นหัวข้อที่ดีที่สุด"],"tip":"คำว่า 'proposed' ในบทความสำคัญมาก — บ่งบอกว่ายังเป็นแค่ข้อเสนอ ยังไม่ใช่การตัดสินใจสุดท้าย หัวข้อที่ใช้คำเด็ดขาดเกินไป (banned, forever, victory) มักผิด"},{"q":"Passage: \"A local high school's robotics team won first place at the national competition this weekend, beating teams from over 50 schools. The team, which has only been together for two years, credits their success to daily practice and strong teamwork.\" Question: What would be the best headline for this article?","choices":["Young Robotics Team Claims National Title After Two Years","School Wins Sports Championship","National Competition Cancelled Due to Weather","Team Practices Daily For Success"],"correct":0,"hint":"หาหัวข้อที่สรุปข้อเท็จจริงหลัก (ชนะเลิศระดับประเทศ) พร้อมรายละเอียดที่โดดเด่น (แค่ 2 ปี)","steps":["ตัวเลือกที่ 2 ผิดประเด็น (โรบอติกส์ไม่ใช่กีฬา 'sports')","ตัวเลือกที่ 3 ผิดข้อเท็จจริงสิ้นเชิง (บทความบอกว่าทีมชนะ ไม่ได้บอกว่าแข่งขันถูกยกเลิก)","ตัวเลือกที่ 4 แคบเกินไป (จับแค่รายละเอียดการฝึกซ้อม ไม่ได้พูดถึงผลการแข่งขันซึ่งเป็นประเด็นหลัก)","ตัวเลือกที่ 1 สรุปข้อเท็จจริงหลัก (ชนะเลิศระดับประเทศ) พร้อมจุดเด่น (แค่ 2 ปี) ได้ครบถ้วนและถูกต้อง"],"tip":"ระวังตัวเลือกที่ใช้คำผิดหมวดหมู่โดยสิ้นเชิง (เช่น 'sports championship' สำหรับการแข่งขันหุ่นยนต์) เป็นตัวลวงที่สังเกตได้ง่ายถ้าอ่านบทความให้ครบ"},{"q":"Passage: \"A popular coffee chain announced it will raise prices by an average of 5% next month, citing higher costs for coffee beans and labor. The company says it will also introduce a new loyalty program to help offset the increase for regular customers.\" Question: What would be the best headline for this article?","choices":["Coffee Chain Raises Prices, Introduces Loyalty Program","Coffee Prices Skyrocket Overnight","Coffee Company Faces Financial Collapse","New Loyalty Program Launches Nationwide"],"correct":0,"hint":"หาหัวข้อที่ครอบคลุมทั้งสองประเด็นหลักของข่าว (ขึ้นราคา และโปรแกรมสมาชิก) โดยไม่พูดเกินจริง","steps":["ตัวเลือกที่ 2 พูดเกินจริง ('skyrocket' หมายถึงพุ่งสูงมาก แต่บทความบอกแค่ 5% ซึ่งไม่ใช่การพุ่งสูงแบบฉับพลัน)","ตัวเลือกที่ 3 ไม่มีข้อมูลสนับสนุนในบทความ (ไม่ได้บอกว่าบริษัทกำลังจะล้มละลาย)","ตัวเลือกที่ 4 แคบเกินไป (จับแค่โปรแกรมสมาชิก ไม่ได้พูดถึงการขึ้นราคาซึ่งเป็นประเด็นหลัก)","ตัวเลือกที่ 1 ครอบคลุมทั้งสองประเด็นหลักอย่างเป็นกลาง ตรงกับเนื้อหาบทความมากที่สุด"],"tip":"ตัวเลขเปอร์เซ็นต์ที่ระบุชัดเจน (5%) ควรเทียบกับคำที่ใช้ในหัวข้อ — คำที่แสดงความรุนแรงเกินจริง (skyrocket, plummet, collapse) มักไม่ตรงกับตัวเลขที่ระบุจริงถ้าตัวเลขนั้นไม่ได้สูง/ต่ำมากจริงๆ"},{"q":"Passage: \"Scientists have discovered a new species of frog in a remote rainforest region. The frog, notable for its bright blue coloring, is believed to be highly sensitive to changes in its environment, making it an important indicator species for forest health.\" Question: What would be the best headline for this article?","choices":["New Blue Frog Species Discovered, Signals Forest Health","Frogs Are Going Extinct Worldwide","Scientists Explore Remote Rainforest Region","Blue Frog Named Official National Symbol"],"correct":0,"hint":"หาหัวข้อที่ครอบคลุมทั้งการค้นพบและความสำคัญของมัน (ตัวชี้วัดสุขภาพป่า) โดยไม่เพิ่มข้อมูลที่ไม่มีในบทความ","steps":["ตัวเลือกที่ 2 ไม่มีข้อมูลสนับสนุนเลย (บทความไม่ได้พูดถึงการสูญพันธุ์)","ตัวเลือกที่ 3 กว้างเกินไปและแคบเกินไปพร้อมกัน (พูดแค่การสำรวจ ไม่ได้พูดถึงการค้นพบสายพันธุ์ใหม่ซึ่งเป็นประเด็นหลัก)","ตัวเลือกที่ 4 เป็นข้อมูลที่ไม่มีในบทความเลย (ไม่ได้บอกว่าถูกตั้งเป็นสัญลักษณ์ประจำชาติ)","ตัวเลือกที่ 1 ครอบคลุมทั้งการค้นพบและความสำคัญเชิงนิเวศ (ตัวชี้วัดสุขภาพป่า) ตรงกับเนื้อหาบทความมากที่สุด"],"tip":"ระวังตัวเลือกที่เติมรายละเอียดที่ 'ฟังดูสมเหตุสมผล' แต่ไม่มีอยู่จริงในบทความ (เช่น การตั้งเป็นสัญลักษณ์ประจำชาติ) เป็นกับดักที่พบบ่อยในโจทย์เลือกพาดหัวข่าว"}]}
);

